// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "./ExactlyProtocol.sol";

contract ExactlyProtocolTest is Test {
    ExactlyProtocol protocol;

    function setUp() public {
        protocol = new ExactlyProtocol();
    }

    function testDeposit() public {
        uint256 amount = 100 ether;
        protocol.deposit(amount);
        assertEq(protocol.balances(address(this)), amount);
    }

    function testWithdraw() public {
        uint256 amount = 100 ether;
        protocol.deposit(amount);
        protocol.withdraw(amount);
        assertEq(protocol.balances(address(this)), 0);
    }

    function testReentrancyAttack() public {
        ReentrancyAttacker attacker = new ReentrancyAttacker(address(protocol));
        vm.expectRevert();
        attacker.attack();
    }

    function testFailWithdrawInsufficientBalance() public {
        uint256 amount = 100 ether;
        protocol.withdraw(amount);
    }
}

contract ReentrancyAttacker {
    ExactlyProtocol protocol;

    constructor(address _protocol) {
        protocol = ExactlyProtocol(_protocol);
    }

    function attack() external {
        protocol.deposit(1 ether);
        protocol.withdraw(1 ether);
    }

    receive() external payable {
        if (address(protocol).balance > 0) {
            protocol.withdraw(1 ether);
        }
    }
}
